const items = $input.all();
const datos = items.map(i => i.json);

// Buscar el mensaje del primer nodo Code
const mensaje = $('Code in JavaScript').first().json.mensaje;

return [{ 
  json: { 
    datos: datos,
    mensaje: mensaje,
    total_registros: datos.length
  } 
}];

const respuesta = $input.first().json.content.parts[0].text;

let filas = [];
try {
  const inicio = respuesta.indexOf('INICIO_JSON');
  const fin = respuesta.indexOf('FIN_JSON');
  if (inicio !== -1 && fin !== -1) {
    const jsonStr = respuesta.substring(inicio + 11, fin).trim();
    const parsed = JSON.parse(jsonStr);
    filas = parsed.informe && parsed.informe.length > 0 
      ? parsed.informe 
      : [{ resultado: 'No se encontraron registros que cumplan el criterio solicitado' }];
  } else {
    filas = [{ resultado: respuesta.substring(0, 500) }];
  }
} catch(e) {
  filas = [{ error: e.message }];
}

